class Solution:
    def minTime(self, n, k, m, time, mul):
        from itertools import combinations
        import math
        INF = float('inf')
        full = (1 << n) - 1
        # dp[mask][stage] = min total time when 'mask' people are on destination side
        dp = [[INF] * m for _ in range(1 << n)]
        dp[0][0] = 0.0
        # BFS/DP: process states in order of time (Dijkstra-like)
        import heapq
        heap = [(0.0, 0, 0)]  # (time, mask, stage)
        while heap:
            t, mask, stage = heapq.heappop(heap)
            if t > dp[mask][stage]:
                continue
            if mask == full:
                return round(t, 5)
            remaining = [i for i in range(n) if not (mask >> i & 1)]
            # choose 1..k people to send across
            for r in range(1, min(k, len(remaining)) + 1):
                for group in combinations(remaining, r):
                    cross_time = max(time[i] for i in group) * mul[stage]
                    new_stage = (stage + math.floor(cross_time)) % m
                    new_mask = mask | sum(1 << i for i in group)
                    if new_mask == full:
                        nt = t + cross_time
                        if nt < dp[full][new_stage]:
                            dp[full][new_stage] = nt
                            heapq.heappush(heap, (nt, full, new_stage))
                    else:
                        # someone must return
                        on_dest = [i for i in range(n) if new_mask >> i & 1]
                        for ret in on_dest:
                            ret_time = time[ret] * mul[new_stage]
                            ret_stage = (new_stage + math.floor(ret_time)) % m
                            after_mask = new_mask ^ (1 << ret)
                            nt = t + cross_time + ret_time
                            if nt < dp[after_mask][ret_stage]:
                                dp[after_mask][ret_stage] = nt
                                heapq.heappush(heap, (nt, after_mask, ret_stage))
        return -1.0 if all(dp[full][s] == INF for s in range(m)) else round(min(v for v in dp[full] if v < INF), 5)

