var minTime = function(n, k, m, time, mul) {
    const INF = Infinity;
    const full = (1 << n) - 1;
    const dp = Array.from({length: 1 << n}, () => new Array(m).fill(INF));
    dp[0][0] = 0.0;
    // min-heap: [time, mask, stage]
    const heap = [[0.0, 0, 0]];
    function heapPush(h, item) {
        h.push(item);
        let i = h.length - 1;
        while (i > 0) {
            const parent = (i - 1) >> 1;
            if (h[parent][0] > h[i][0]) { [h[parent], h[i]] = [h[i], h[parent]]; i = parent; } else break;
        }
    }
    function heapPop(h) {
        const top = h[0];
        const last = h.pop();
        if (h.length > 0) {
            h[0] = last;
            let i = 0;
            while (true) {
                let s = i, l = 2*i+1, r = 2*i+2;
                if (l < h.length && h[l][0] < h[s][0]) s = l;
                if (r < h.length && h[r][0] < h[s][0]) s = r;
                if (s !== i) { [h[s], h[i]] = [h[i], h[s]]; i = s; } else break;
            }
        }
        return top;
    }
    function getCombinations(arr, r) {
        const result = [];
        function bt(start, combo) {
            if (combo.length === r) { result.push([...combo]); return; }
            for (let i = start; i < arr.length; i++) { combo.push(arr[i]); bt(i+1, combo); combo.pop(); }
        }
        bt(0, []);
        return result;
    }
    while (heap.length > 0) {
        const [t, mask, stage] = heapPop(heap);
        if (t > dp[mask][stage]) continue;
        if (mask === full) return Math.round(t * 100000) / 100000;
        const remaining = [];
        for (let i = 0; i < n; i++) if (!(mask >> i & 1)) remaining.push(i);
        for (let r = 1; r <= Math.min(k, remaining.length); r++) {
            for (const group of getCombinations(remaining, r)) {
                const crossTime = Math.max(...group.map(i => time[i])) * mul[stage];
                const newStage = (stage + Math.floor(crossTime)) % m;
                let newMask = mask;
                for (const i of group) newMask |= (1 << i);
                if (newMask === full) {
                    const nt = t + crossTime;
                    if (nt < dp[full][newStage]) {
                        dp[full][newStage] = nt;
                        heapPush(heap, [nt, full, newStage]);
                    }
                } else {
                    const onDest = [];
                    for (let i = 0; i < n; i++) if (newMask >> i & 1) onDest.push(i);
                    for (const ret of onDest) {
                        const retTime = time[ret] * mul[newStage];
                        const retStage = (newStage + Math.floor(retTime)) % m;
                        const afterMask = newMask ^ (1 << ret);
                        const nt = t + crossTime + retTime;
                        if (nt < dp[afterMask][retStage]) {
                            dp[afterMask][retStage] = nt;
                            heapPush(heap, [nt, afterMask, retStage]);
                        }
                    }
                }
            }
        }
    }
    const best = Math.min(...dp[full]);
    return best === INF ? -1.0 : Math.round(best * 100000) / 100000;
};
